#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX 100005
int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}
int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int sums[N * (N + 1) / 2];
    int index = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            int sum = 0;
            for (int k = i; k <= j; k++) {
                sum += A[k];
            }
            sums[index++] = sum;
        }
    }
    qsort(sums, N * (N + 1) / 2, sizeof(int), compare);
    for (int i = 0; i < K; i++) {
        printf("%d ", sums[i]);
    }
    return 0;
}

