import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int K = scanner.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        int[] sums = new int[N * (N + 1) / 2];
        int index = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i; j < N; j++) {
                int sum = 0;
                for (int k = i; k <= j; k++) {
                    sum += A[k];
                }
                sums[index++] = sum;
            }
        }
        Arrays.sort(sums);
        for (int i = sums.length - 1; i >= sums.length - K; i--) {
            System.out.print(sums[i] + " ");
        }
    }
}

