const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', function(line) {
    input.push(line);
}).on('close', function() {
    let [N, K] = input[0].split(' ').map(x => parseInt(x));
    let A = input[1].split(' ').map(x => parseInt(x));
    let sums = [];
    for (let i = 0; i < N; i++) {
        for (let j = i; j < N; j++) {
            let sum = 0;
            for (let k = i; k <= j; k++) {
                sum += A[k];
            }
            sums.push(sum);
        }
    }
    sums.sort((a, b) => b - a);
    for (let i = 0; i < K; i++) {
        process.stdout.write(sums[i] + ' ');
    }
});
